import{_ as t,o as s,c as l,O as r}from"./chunks/framework.0d5b6918.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"materials/service-packages.md","filePath":"materials/service-packages.md","lastUpdated":1776439080000}'),n={name:"materials/service-packages.md"};function i(d,a,e,c,p,o){return s(),l("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Cooperation</p><h1>启动方式 / 标准服务包</h1><div class="brand-hero__panel"><span class="brand-pill">Service Entry</span><strong>璇络(ExecFabric) 当前的启动方式围绕真实流程梳理、受控执行接入和小型正式交付三类项目展开，重点是把第一阶段做成可验证、可交付、可复用的闭环。</strong><p>合作判断的重点不是功能名有多少，而是当前场景是否明确、边界是否清晰、第一阶段是否能形成稳定结果。</p></div><p class="brand-lead"> 更常见的启动方式，是围绕 <strong>一个高频、重复、规则相对明确的流程</strong> 建立最小闭环。这样更容易验证投入产出，也更容易形成后续扩展的基础。 </p><p class="brand-lead"> 这页回答的是“什么时候该进入项目交付沟通”，不是“所有用户下一步都应该买什么”。 如果对方还处在免费体验、个人空间脚本位扩容或标准团队版月租 / 年租阶段，优先看会员与支付路径； 只有进入更强隔离、内网、本地桥接或正式项目边界时，才该切到这页。 </p><p class="brand-lead"> 当前更适合把公开体验、标准团队版、正式项目交付和私有化边界分开讲清楚， 让不同阶段的客户都能快速找到合适入口。 </p><div class="brand-chip-list"><span class="brand-chip">先做一个点</span><span class="brand-chip">先收口范围</span><span class="brand-chip">适合真实场景</span><span class="brand-chip">支持正式交付</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="/contact.html#lead-form">沟通具体场景</a><a class="cta-button" href="../product/editions.html">查看版本阶段与升级路径</a><a class="cta-button" href="../product/implementation-training.html">查看培训与实施服务说明</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // SERVICE PACKAGES</span><span>MAT 04</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">entry</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">one painful flow first</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">mode</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">delivery</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">controlled execution</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">goal</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">delivery_value</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">repeatable_solution</span></span></div><div class="matrix-panel__callout">DON&#39;T START WITH A BIG EMPTY SYSTEM</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">status</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">open</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">real scenarios</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">style</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">small first</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Package A</p><h2>流程自动化启动包</h2><p>面向报表汇总、数据清洗、文件处理、导入导出等高频重复流程，先把单点流程稳定跑通。</p><ul class="brand-list"><li>先按一个最痛流程收口</li><li>优先验证“能不能省时间”</li><li>适合试点项目和第一阶段验证</li></ul></article><article class="brand-card"><p class="brand-kicker">Package B</p><h2>脚本接入与治理包</h2><p>面向已存在脚本或运维动作，但缺少统一入口、执行前确认、历史留痕和治理边界的场景。</p><ul class="brand-list"><li>脚本 / Skill 接入</li><li>执行前确认与风险分级</li><li>历史记录与失败原因可见</li></ul></article><article class="brand-card"><p class="brand-kicker">Package C</p><h2>小型私有化交付包</h2><p>面向已经超出标准团队版边界，需要更强隔离、本地数据或本地脚本接入、正式治理要求和企业 1.0 单租户交付的场景。</p><ul class="brand-list"><li>独立租户与权限边界</li><li>本地执行桥接与审计</li><li>支持正式项目交付</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Entry Split</p><h2>哪些场景先不要直接按项目交付谈</h2><table class="cooperation-start-table"><thead><tr><th>当前状态</th><th>更适合的路径</th><th>为什么</th></tr></thead><tbody><tr><td>还在第一次体验平台</td><td>先走免费线</td><td>先确认这是不是值得继续了解的平台，不急着进入项目报价</td></tr><tr><td>只是个人继续接脚本</td><td>先走本地脚本位增购</td><td>这属于轻量扩容，不等于正式团队协作或企业交付</td></tr><tr><td>已经开始多人协作，但需求仍偏标准</td><td>先走团队版月租 / 年租正式租户入口</td><td>先用标准 SaaS 路径验证协作是否成立，再决定要不要进入更重交付</td></tr><tr><td>需要更强隔离、内网、本地执行桥接或正式项目验收</td><td>进入项目交付沟通</td><td>这时才真正需要谈部署、交付边界、里程碑和服务包</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Good Fit</p><h2>当前更适合优先沟通的几类项目</h2><ul class="brand-list"><li>报表、文件、数据处理这类高频重复流程</li><li>已有 Python 脚本，需要接成统一入口的场景</li><li>本地环境、本地脚本或内网资源需要被受控调度的场景</li><li>标准团队版已经不够，需要更强隔离、定制页面或正式交付边界的场景</li></ul></article><article class="brand-card"><p class="brand-kicker">Not A Good Start</p><h2>当前不建议直接启动的事项</h2><ul class="brand-list"><li>范围过宽、没有明确第一阶段边界的定制需求</li><li>每个客户都要求深度定制，却没有复用空间和不包含项</li><li>默认整仓源码交付，但又希望平台后面还能持续复用和升级</li><li>只想做一个“AI 聊天壳”，没有真实执行场景</li><li>预算极低、但预期长期驻场式支持</li><li>没有脚本、没有流程、没有要解决的具体问题，却先想做大系统</li></ul></article></section><section class="brand-card"><p class="brand-kicker">How We Start</p><h2>标准启动方式</h2><table class="cooperation-start-table"><thead><tr><th>步骤</th><th>要做什么</th><th>目的</th></tr></thead><tbody><tr><td>01</td><td>先说清当前最痛的流程名称</td><td>避免一开始就把需求谈得过大、过空</td></tr><tr><td>02</td><td>说明当前输入、输出和执行频率</td><td>判断这个点值不值得先自动化</td></tr><tr><td>03</td><td>按一个点收口范围、周期和不包含项</td><td>快速给出正式方案和报价</td></tr><tr><td>04</td><td>先交付最小闭环，再决定第二阶段</td><td>降低决策难度，也更容易形成复用案例</td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Cooperation Ladder</p><h2>当前五种合作方式怎么选</h2><table class="cooperation-start-table"><thead><tr><th>合作方式</th><th>适合谁</th><th>当前更适合解决什么</th><th>默认不等于什么</th></tr></thead><tbody><tr><td>免费演示</td><td>第一次了解平台的人</td><td>先确认执行链路、产品定位和是否值得继续深入</td><td>不等于企业正式生产环境</td></tr><tr><td>付费咨询 / POC</td><td>已有场景，但范围还没收口的团队</td><td>先把目标、范围、预算和实施顺序说清楚</td><td>不等于完整正式交付或无限轮需求沟通</td></tr><tr><td>团队版 SaaS</td><td>标准能力、较轻协作、预算有限的团队</td><td>低门槛进入正式使用和标准团队协作</td><td>不等于独立私有化或深度定制项目</td></tr><tr><td>轻量私有化部署</td><td>想先落一个正式独立环境的小微团队</td><td>用较小范围先跑通一个正式闭环</td><td>不等于复杂定制开发或长期驻场</td></tr><tr><td>标准私有化部署</td><td>需要内网、合规、更强边界和正式验收的客户</td><td>承接独立部署、正式培训和长期基础支持</td><td>不等于默认包含全部新增功能和无限支持</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Implementation</p><h2>实施和培训当前怎么安排</h2><ul class="brand-list"><li>先按范围确认、环境准备、能力接入、联调验收、培训上线这五步推进。</li><li>培训按角色讲，不把业务负责人、管理员、普通使用人和 IT 运维混成一套大课。</li><li>上线时不只交一个账号，还会同时交付使用说明、交付说明、热更新说明和结果入口说明。</li></ul></article><article class="brand-card"><p class="brand-kicker">Support Boundary</p><h2>后续支持边界先讲清楚</h2><ul class="brand-list"><li>已交付范围内问题排查、基础答疑和少量脚本更新通常属于标准支持。</li><li>新增功能、大范围页面改造、深度第三方集成和驻场陪跑应单独评估。</li><li>当前建议默认按工作日支持窗口理解，更高响应等级应单独约定。</li></ul><p><a href="../product/implementation-training.html">查看培训与实施服务说明</a></p></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Why This Structure</p><h2>这种合作结构的直接价值</h2><ul class="brand-list"><li>第一阶段边界更清晰，便于评估和验收</li><li>更容易在短周期内看到真实结果</li><li>能先验证流程价值，再决定是否进入第二阶段扩展</li><li>适合从标准团队版继续上探到企业版和私有化场景</li></ul></article><article class="brand-card"><p class="brand-kicker">Preparation</p><h2>进入评估前建议准备</h2><ul class="brand-list"><li>一个真实流程名称，以及当前最痛的环节</li><li>输入、输出、执行频率和当前处理方式</li><li>现有脚本、文件样例、接口说明或执行规则</li><li>第一阶段希望达成的结果和时间要求</li></ul></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>带一个真实流程进入评估，会更高效</h2><p class="brand-lead">进入具体沟通后，重点通常不是继续讨论抽象概念，而是尽快把流程范围、输入输出、周期和第一阶段目标对齐。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./membership-benefits-pricing.html"><span>Pricing</span><strong>先看会员与价格路径</strong></a><a class="brand-link-card" href="/contact.html#lead-form"><span>Lead</span><strong>沟通真实场景</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>客户交付与使用说明</strong></a><a class="brand-link-card" href="../product/implementation-training.html"><span>Training</span><strong>培训与实施安排</strong></a><a class="brand-link-card" href="./source-delivery-boundaries.html"><span>Boundary</span><strong>源码与授权边界</strong></a><a class="brand-link-card" href="../product/onboarding-checklist.html"><span>Checklist</span><strong>客户接入准备清单</strong></a><a class="brand-link-card" href="../product/editions.html"><span>Roadmap</span><strong>版本阶段与升级路径</strong></a></div></div></section></div>',1)]))}const h=t(n,[["render",i]]);export{b as __pageData,h as default};
